demoFilteredFamilies.representativeSql:
SELECT a.Description,b.ApprovedDate,year(b.ApprovedDate),b.Number01,b.PartNum,b.RevisionNum,b.RevShortDesc,b.RevDescription,c.PartDescription
 FROM PUB.ECOGroup a
LEFT JOIN PUB.ECORev b ON (a.Company = b.Company AND a.GroupID = b.GroupID)
LEFT JOIN PUB.Part  c ON (c.Company = b.Company AND c.PartNum = b.PartNum)
WHERE a.Company ='jctimes' AND a.GroupID LIKE 'jsb%' AND a.GroupID <>'jsb5555'
AND b.ApprovedDate >='2018-1-1' AND b.Number01 <>'0'
 ${if (len(完工日期大于)==0,"","and b.ApprovedDate>='"+完工日期大于+"'")}
 ${if (len(完工日期小于)==0,"","and b.ApprovedDate<='"+完工日期小于+"'")}
  ${if (len(设计员)==0,"","and a.Description='"+设计员+"'")}
